<?php use Kovcheg\Blog\Blog;$labels=['post'=>'Публикация','page'=>'Страница','portfolio'=>'Портфолио'];?>
<div class="page-head"><div><h1>Материалы</h1><p>Записи блога, обычные страницы и работы портфолио.</p></div><div class="editor-actions"><a class="button primary" href="<?=e(app_url('/studio/content/new?type=post'))?>">+ Публикация</a><a class="button" href="<?=e(app_url('/studio/content/new?type=page'))?>">+ Страница</a><a class="button" href="<?=e(app_url('/studio/content/new?type=portfolio'))?>">+ Портфолио</a></div></div>
<form class="filters" method="get" action="<?=e(app_url('/studio/content'))?>"><select name="type"><option value="">Все типы</option><?php foreach($labels as $key=>$label):?><option value="<?=e($key)?>" <?=$type===$key?'selected':''?>><?=e($label)?></option><?php endforeach;?></select><select name="status"><option value="">Все статусы</option><?php foreach(['draft'=>'Черновик','published'=>'Опубликовано','scheduled'=>'Запланировано','private'=>'Приватно'] as $key=>$label):?><option value="<?=e($key)?>" <?=$status===$key?'selected':''?>><?=e($label)?></option><?php endforeach;?></select><input name="q" value="<?=e($search)?>" placeholder="Поиск по заголовку"><button class="button">Найти</button><?php if($type!==''||$status!==''||$search!==''):?><a class="button" href="<?=e(app_url('/studio/content'))?>">Сбросить</a><?php endif;?></form>
<?php if($entries):?><table class="content-table"><thead><tr><th>Материал</th><th>Тип</th><th>Автор</th><th>Статус</th><th>Комментарии</th><th>Обновлён</th><th></th></tr></thead><tbody><?php foreach($entries as $entry):?><tr><td><b><?=e($entry['title'])?></b><small>/<?=e($entry['slug'])?></small></td><td><?=e($labels[$entry['type']]??$entry['type'])?></td><td><?=e($entry['author_name'])?></td><td><span class="status <?=e($entry['status'])?>"><?=e($entry['status'])?></span></td><td><?=(int)$entry['comment_count']?></td><td><?=e($entry['updated_at'])?></td><td><div class="table-actions"><?php if($entry['status']==='published'):?><a class="button small" target="_blank" href="<?=e(Blog::entryUrl($entry))?>">Просмотр</a><?php endif;?><a class="button small" href="<?=e(app_url('/studio/content/'.(int)$entry['id'].'/edit'))?>">Изменить</a><form method="post" action="<?=e(app_url('/studio/content/'.(int)$entry['id'].'/duplicate'))?>"><?=csrf_field()?><button class="button small">Копия</button></form><form method="post" data-confirm="Переместить материал в корзину?" action="<?=e(app_url('/studio/content/'.(int)$entry['id'].'/trash'))?>"><?=csrf_field()?><button class="button small danger">В корзину</button></form></div></td></tr><?php endforeach;?></tbody></table><?php else:?><div class="empty-state">Материалы не найдены.</div><?php endif;?>
